import { Instructor, OpenAI } from 'instructor';
import { z } from 'zod';

const client = new Instructor(new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
}));

const TicketSchema = z.object({
  customerId: z.string(),
  issueType: z.enum(['billing', 'technical', 'order', 'other']),
  priority: z.enum(['low', 'medium', 'high']),
  description: z.string(),
});

type Ticket = z.infer<typeof TicketSchema>;

const result = await client.chat.completions.create({
  model: 'gpt-4o',
  schema: TicketSchema,
  messages: [
    {
      role: 'system',
      content: 'Extract ticket details from customer message',
    },
    {
      role: 'user',
      content: 'My order #12345 payment failed twice',
    },
  ],
}) as Ticket;

console.log(result.customerId); // '12345'

from pydantic import BaseModel, Field
from typing import Literal, Optional
from instructor import from_openai

class EscalationTrigger(BaseModel):
    trigger_type: Literal['vip_customer', 'legal_threat', 'repeated_failure']
    confidence: float

class AgentResponse(BaseModel):
    primary_action: str
    follow_up: str
    escalation: Optional[EscalationTrigger] = None

client = from_openai(OpenAI())

response = client.chat.completions.create(
    model="gpt-4o",
    response_model=AgentResponse,
    messages=[
        {"role": "user", "content": "This is the 5th time! I want to speak to your manager NOW!"}
    ]
)

if response.model.escalation:
    print(f"ESCALATE: {response.model.escalation.trigger_type}")

