from vex import verify, Guardrail
from pydantic import BaseModel

class ToneCheck(Guardrail):
    name = "empathetic_tone"
    prompt = "Rate empathy 1-10. Must be >=8 for customer support"

class EscalationCheck(Guardrail):
    name = "escalation_trigger"
    prompt = "Should this be escalated to human? Y/N only"

@verify(guards=[ToneCheck(), EscalationCheck()])
def generate_response(ticket: dict) -> str:
    from instructor import from_openai
    client = from_openai(OpenAI())
    return client.chat.completions.create(
        model="gpt-4o",
        response_model=str,
        messages=[
            {"role": "system", "content": "Always empathetic, professional tone"},
            {"role": "user", "content": f"Ticket: {ticket}"}
        ]
    ).model

response = generate_response({"issue": "very angry customer"})
print(response)  # Vex ensures proper tone/escalation

import { verify } from 'vex-sdk';
import { Instructor, OpenAI } from 'instructor';
import { z } from 'zod';

const instructor = new Instructor(new OpenAI());

const ticketSchema = z.object({
  customerId: z.string(),
  issueType: z.enum(['billing', 'technical', 'order']),
  priority: z.enum(['low', 'medium', 'high']),
});

type Ticket = z.infer<typeof ticketSchema>;

const extractTicket = verify<Ticket>({
  guards: ['pii_filter', 'policy_compliance', 'response_accuracy'],
  fn: async (query: string) => {
    return await instructor.chat.completions.create({
      model: 'gpt-4o',
      schema: ticketSchema,
      messages: [{ role: 'user', content: query }],
    }) as Ticket;
  },
});

const ticket = await extractTicket(
  'Contact 555-1234 re: order #VIP001 payment issue'
);
console.log(ticket.customerId); // 'VIP001' (phone filtered by Vex)
